class Payload():
    def __init__(self, raw_url):
        self.url = raw_url

    def verify_url(self):
        if self.url.startswith("http"):
            return self.url
        return None

    def redirect_to_url(self):
        url = self.verify_url()
        if not url:
            abort(404)
        return redirect(url)

