from urllib.parse import unquote

def get_query_params(url):
    start = url.find('?') + 1
    end = url.find('#')
    if end == -1:
        end = len(url)

    params = url[start:end]
    split_params = params.split('&')
    q_params = {}

    for pair in split_params:
        k, v = pair.split('=')
        v = unquote(v)
        if k in q_params:
            q_params[k] += ',' + v
        else:
            q_params[k] = v

    return q_params

